int maximum(int a, int b, int c){
	int k;
	if( a <= b )
		k = b;
	else
		k = a;
	if( k <= c )
		return c;
	else
		return k;
}

inline int SCORE(int *input_itemsets_l, int i, int j) {
	return input_itemsets_l[j + i * (BLOCK_SIZE + 1)];
}
inline int &SCORE(int *input_itemsets_l, int i, int j) {
	return input_itemsets_l[j + i * (BLOCK_SIZE + 1)];
}
inline int REF(int *reference_l, int i, int j) {
	return reference_l[j + i * BLOCK_SIZE];
}
inline int &REF(int *reference_l, int i, int j) {
	return reference_l[j + i * BLOCK_SIZE];
}

void nw_kernel1(int *reference_d, int *input_itemsets_d, int *output_itemsets_d,
                int cols, int penalty, int blk, int block_width, int worksize,
                int offset_r, int offset_c)
{
	int base = offset_r * cols + offset_c;

#pragma omp parallel num_threads(BLOCK_SIZE)
	{
		int tx = omp_get_thread_num();

		int b_index_x = omp_get_thread_num();
		int bx = b_index_x;
		b_index_x = bx;
		int b_index_y = blk - 1 - bx;

		int index = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
		int index_n = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
		int index_w = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
		int index_nw = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

		int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
		int reference_l[BLOCK_SIZE * BLOCK_SIZE];

		if (tx == 0) {
			SCORE(input_itemsets_l, tx, 0) = input_itemsets_d[index_nw + tx];
		}

#pragma omp barrier

		for (int ty = 0; ty < BLOCK_SIZE; ty++) {
			REF(reference_l, ty, tx) = reference_d[index + cols * ty];
		}

#pragma omp barrier

		SCORE(input_itemsets_l, (tx + 1), 0) = input_itemsets_d[index_w + cols * tx];

#pragma omp barrier

		SCORE(input_itemsets_l, 0, (tx + 1)) = input_itemsets_d[index_n];

#pragma omp barrier

		for (int m = 0; m < BLOCK_SIZE; m++) {

			if (tx <= m) {

				int t_index_x = tx + 1;
				int t_index_y = m - tx + 1;

				SCORE(input_itemsets_l, t_index_y, t_index_x) = maximum(
					SCORE(input_itemsets_l, (t_index_y - 1), (t_index_x - 1)) + REF(reference_l, (t_index_y - 1), (t_index_x - 1)),
					SCORE(input_itemsets_l, (t_index_y), (t_index_x - 1)) - (penalty),
					SCORE(input_itemsets_l, (t_index_y - 1), (t_index_x)) - (penalty));
			}
#pragma omp barrier
		}

#pragma omp barrier

		for (int m = BLOCK_SIZE - 2; m >= 0; m--) {

			if (tx <= m) {

				int t_index_x = tx + BLOCK_SIZE - m;
				int t_index_y = BLOCK_SIZE - tx;

				SCORE(input_itemsets_l, t_index_y, t_index_x) = maximum(
					SCORE(input_itemsets_l, (t_index_y - 1), (t_index_x - 1)) + REF(reference_l, (t_index_y - 1), (t_index_x - 1)),
					SCORE(input_itemsets_l, (t_index_y), (t_index_x - 1)) - (penalty),
					SCORE(input_itemsets_l, (t_index_y - 1), (t_index_x)) - (penalty));
			}
#pragma omp barrier
		}

		for (int ty = 0; ty < BLOCK_SIZE; ty++) {
			input_itemsets_d[index + cols * ty] = SCORE(input_itemsets_l, (ty + 1), (tx + 1));
		}
	}
}

