	gettimeofday(&t, NULL);
	return t.tv_sec + t.tv_usec * 1e-6;
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> [-p platform] [-d device]\n", argv[0]);
	fprintf(stderr, "\t<dimension>  - x and y dimensions\n");
	fprintf(stderr, "\t<penalty> - penalty(positive integer)\n");
	fprintf(stderr, "\t<file> - filename\n");
	fprintf(stderr, "\t[platform] - platform id\n");
	fprintf(stderr, "\t[device] - device id\n");
	exit(1);
}

int main(int argc, char **argv){

	printf("WG size of kernel = %d \n", BLOCK_SIZE);

	int max_rows, max_cols, penalty;
	char * tempchar;

	if (argc >= 4)
	{
		max_rows = atoi(argv[1]);
		max_cols = atoi(argv[1]);
		penalty = atoi(argv[2]);
		tempchar = argv[3];

		int cur_arg;
		for (cur_arg = 1; cur_arg < argc; cur_arg++) {
			if (strcmp(argv[cur_arg], "-p") == 0) {
				if (argc >= cur_arg + 1) {
					// platform_id_inuse = atoi(argv[cur_arg + 1]);
					cur_arg++;
				}
			}
			else if (strcmp(argv[cur_arg], "-d") == 0) {
				if (argc >= cur_arg + 1) {
					// device_id_inuse = atoi(argv[cur_arg + 1]);
					cur_arg++;
				}
			}
		}
	}
	else {
		usage(argc, argv);
	}

	if (atoi(argv[1]) % 16 != 0) {
		fprintf(stderr, "The dimension values must be a multiple of 16\n");
		exit(1);
	}

	max_rows = max_rows + 1;
	max_cols = max_cols + 1;

	int *reference;
	int *input_itemsets;
	int *output_itemsets;

	reference = (int *)malloc(max_rows * max_cols * sizeof(int));
	input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
	output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

	srand(7);

	for (int i = 0; i < max_cols; i++) {
		for (int j = 0; j < max_rows; j++) {
			input_itemsets[i * max_cols + j] = 0;
		}
	}

	for (int i = 1; i < max_rows; i++) {
		input_itemsets[i * max_cols] = rand() % 10 + 1;
	}

	for (int j = 1; j < max_cols; j++) {
		input_itemsets[j] = rand() % 10 + 1;
	}

	for (int i = 1; i < max_cols; i++) {
		for (int j = 1; j < max_rows; j++) {
			reference[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
		}
	}

	for (int i = 1; i < max_rows; i++)
		input_itemsets[i * max_cols] = -i * penalty;
	for (int j = 1; j < max_cols; j++)
		input_itemsets[j] = -j * penalty;

	int worksize = max_cols - 1;
	printf("worksize = %d\n", worksize);

	int offset_r = 0, offset_c = 0;
	int block_width = worksize / BLOCK_SIZE;

	printf("Processing upper-left matrix\n");
	for (int blk = 1; blk <= worksize / BLOCK_SIZE; blk++) {
		nw_kernel1(reference, input_itemsets, output_itemsets,
			max_cols, penalty, blk, block_width, worksize,
			offset_r, offset_c);
	}

	printf("Processing lower-right matrix\n");
	for (int blk = worksize / BLOCK_SIZE - 1; blk >= 1; blk--) {
		nw_kernel2(reference, input_itemsets, output_itemsets,
			max_cols, penalty, blk, block_width, worksize,
			offset_r, offset_c);
	}

#ifdef TRACEBACK
	FILE *fpo = fopen("result.txt", "w");
	fprintf(fpo, "print traceback value GPU:\n");

	for (int i = max_rows - 2, j = max_rows - 2; i >= 0 && j >= 0;) {
		int nw, n, w, traceback;
		if (i == max_rows - 2 && j == max_rows - 2)
			fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
		if (i == 0 && j == 0)
			break;
		if (i > 0 && j > 0) {
			nw = output_itemsets[(i - 1) * max_cols + j - 1];
			w = output_itemsets[i * max_cols + j - 1];
			n = output_itemsets[(i - 1) * max_cols + j];
		}
		else if (i == 0) {
			nw = n = LIMIT;
			w = output_itemsets[i * max_cols + j - 1];
		}
		else if (j == 0) {
			nw = w = LIMIT;
			n = output_itemsets[(i - 1) * max_cols + j];
		}

		int new_nw, new_w, new_n;
		new_nw = nw + reference[i * max_cols + j];
		new_w = w - penalty;
		new_n = n - penalty;

		traceback = maximum(new_nw, new_w, new_n);
		if (traceback == new_nw)
			traceback = nw;
		if (traceback == new_w)
			traceback = w;
		if (traceback == new_n)
			traceback = n;

		fprintf(fpo, "%d ", traceback);

		if (traceback == nw) { i--; j--; continue; }
		else if (traceback == w) { j--; continue; }
		else if (traceback == n) { i--; continue; }
	}
	fclose(fpo);
#endif

	printf("Computation Done\n");

	free(reference);
	free(input_itemsets);
	free(output_itemsets);

	return 0;
}
